import{_ as s,o as e,c as i,a2 as t}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"进程、线程、用户态、内核态与系统调用","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/05-linux-network/04-process-thread-syscall.md","filePath":"05-backend-data/notes/05-linux-network/04-process-thread-syscall.md","lastUpdated":null}'),n={name:"05-backend-data/notes/05-linux-network/04-process-thread-syscall.md"};function l(r,a,d,p,o,h){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="进程、线程、用户态、内核态与系统调用" tabindex="-1">进程、线程、用户态、内核态与系统调用 <a class="header-anchor" href="#进程、线程、用户态、内核态与系统调用" aria-label="Permalink to &quot;进程、线程、用户态、内核态与系统调用&quot;">​</a></h1><p>进程定义资源与隔离边界，线程定义可被调度的执行流，系统调用是用户程序请求内核服务的受控入口。</p><h2 id="_1-进程与线程" tabindex="-1">1. 进程与线程 <a class="header-anchor" href="#_1-进程与线程" aria-label="Permalink to &quot;1. 进程与线程&quot;">​</a></h2><p>进程有虚拟地址空间、凭据、文件描述符表、signal 状态和其他资源。一个进程包含至少一个线程。同进程线程共享代码、heap、全局数据和文件描述符表，但各自拥有线程 ID、寄存器、用户栈、signal mask 和调度状态。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P[&quot;进程：地址空间、凭据、fd 表&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; T1[&quot;线程 1：寄存器、栈、调度状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; T2[&quot;线程 2：寄存器、栈、调度状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; H[&quot;共享 heap 与映射&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; F[&quot;共享 fd 表&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>进程隔离能限制普通内存破坏，但不是完整安全沙箱；同 UID、ptrace 权限、共享文件、IPC 和内核漏洞仍可能跨边界。线程通信便宜但共享数据需同步，一个线程触发的致命 signal 通常终止整个进程。</p><h2 id="_2-创建、执行与回收" tabindex="-1">2. 创建、执行与回收 <a class="header-anchor" href="#_2-创建、执行与回收" aria-label="Permalink to &quot;2. 创建、执行与回收&quot;">​</a></h2><p>Unix 进程创建常涉及 <code>fork</code>/<code>clone</code>，随后 <code>execve</code> 用新程序替换当前进程映像。<code>execve</code> 成功不会返回；PID 保持，地址空间和许多属性被替换，未标记 close-on-exec 的 fd 可能泄漏到新程序。</p><p>父进程用 <code>wait</code>/<code>waitpid</code> 取得退出状态并回收 zombie。退出码是进程间协议；被 signal 终止与正常非零退出应分开记录。shell 中 <code>$?</code> 只保存最近前台 pipeline 的状态。</p><p><code>fork</code> 后多线程子进程在 exec 前只能安全调用有限的 async-signal-safe 函数。现代应用通常使用语言运行时提供的进程启动 API，仍需明确环境变量、工作目录、继承 fd 和取消行为。</p><h2 id="_3-用户态、内核态与权限级别" tabindex="-1">3. 用户态、内核态与权限级别 <a class="header-anchor" href="#_3-用户态、内核态与权限级别" aria-label="Permalink to &quot;3. 用户态、内核态与权限级别&quot;">​</a></h2><p>用户态代码不能直接修改页表、配置设备或任意访问物理内存。系统调用、异常和中断进入内核态；内核验证指针、权限与状态，执行操作后返回。用户态/内核态是 CPU 权限与执行上下文，不等同于普通用户/root：root 进程大部分时间仍在用户态执行。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant A as 应用</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant L as libc或运行时</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant K as Linux内核</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant D as 设备或文件系统</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A-&gt;&gt;L: read(fd, buf, n)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L-&gt;&gt;K: 系统调用入口</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K-&gt;&gt;K: 校验fd、地址与权限</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K-&gt;&gt;D: 获取数据或等待</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D--&gt;&gt;K: 完成或错误</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K--&gt;&gt;L: 返回字节数或错误</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L--&gt;&gt;A: n或-1并设置errno</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>一次 <code>read</code> syscall 不等于一次物理磁盘 I/O：数据可能来自 page cache、pipe 或 socket；也可能只返回部分数据。进入内核有成本，但不能据此盲目减少 syscall；正确批量和缓冲需由 profile/基准验证。</p><h2 id="_4-系统调用返回、errno-与部分结果" tabindex="-1">4. 系统调用返回、errno 与部分结果 <a class="header-anchor" href="#_4-系统调用返回、errno-与部分结果" aria-label="Permalink to &quot;4. 系统调用返回、errno 与部分结果&quot;">​</a></h2><p>Linux 内核接口通常以负错误号表示失败；C 库包装常返回 <code>-1</code> 并设置线程局部 <code>errno</code>。只在调用指示失败后读取 errno。</p><table tabindex="0"><thead><tr><th>errno</th><th>含义</th><th>处理边界</th></tr></thead><tbody><tr><td><code>EINTR</code></td><td>被 signal 中断</td><td>某些调用可重试；先确认是否已有部分进展和截止时间</td></tr><tr><td><code>EAGAIN/EWOULDBLOCK</code></td><td>现在不能完成</td><td>非阻塞 I/O 等待就绪；不是永久故障</td></tr><tr><td><code>EBADF</code></td><td>fd 无效或模式不符</td><td>常是生命周期/并发 bug，不能重试修复</td></tr><tr><td><code>EACCES/EPERM</code></td><td>权限或操作被拒绝</td><td>检查凭据、mode、capability、安全模块</td></tr><tr><td><code>ENOMEM</code></td><td>无法满足内存请求</td><td>受虚拟内存、限制和内核资源影响</td></tr></tbody></table><p>读写允许短结果：请求 4096 字节可能只处理 300 字节。调用者必须循环，并处理 EOF、错误、取消和总上限。写入非幂等设备或协议时，部分写后无条件从头重试会重复数据。</p><h2 id="_5-调度状态与阻塞" tabindex="-1">5. 调度状态与阻塞 <a class="header-anchor" href="#_5-调度状态与阻塞" aria-label="Permalink to &quot;5. 调度状态与阻塞&quot;">​</a></h2><p>可运行线程进入运行队列，由调度器选择在 CPU 上执行。线程可因等待 I/O、futex、定时器、page fault 等睡眠。自愿上下文切换通常来自阻塞；非自愿切换常来自时间片、优先级或被抢占。</p><table tabindex="0"><thead><tr><th>Linux 状态</th><th>含义</th><th>诊断方向</th></tr></thead><tbody><tr><td><code>R</code></td><td>正在运行或可运行</td><td>持续大量 R 结合 quota 看 CPU 饱和</td></tr><tr><td><code>S</code></td><td>可中断睡眠</td><td>网络、定时器、锁等待都可能出现</td></tr><tr><td><code>D</code></td><td>不可中断睡眠</td><td>查看 wchan、内核栈、设备/文件系统证据</td></tr><tr><td><code>T/t</code></td><td>job control 停止或被跟踪</td><td>检查 signal、调试器</td></tr><tr><td><code>Z</code></td><td>已退出未被父进程回收</td><td>修复父进程 wait 逻辑</td></tr></tbody></table><p><code>D</code> 状态下即使 <code>SIGKILL</code> 已挂起，也要等内核路径返回。不能把所有 D 状态都叫“磁盘坏”。</p><h2 id="_6-上下文切换的成本" tabindex="-1">6. 上下文切换的成本 <a class="header-anchor" href="#_6-上下文切换的成本" aria-label="Permalink to &quot;6. 上下文切换的成本&quot;">​</a></h2><p>切换需保存/恢复寄存器和调度状态；进程切换可能改变地址空间，工作集竞争还会造成 CPU cache/TLB 效果。成本取决于架构、工作集和安全缓解，不能用一个固定纳秒值代表所有机器。</p><p>切换数量必须与吞吐、延迟、CPU 和并发量共同解释。I/O 服务在高吞吐下有大量自愿切换可以正常；无用锁竞争、过多 runnable 线程或极短任务会增加调度开销。</p><h2 id="_7-观测进程、线程和-syscall" tabindex="-1">7. 观测进程、线程和 syscall <a class="header-anchor" href="#_7-观测进程、线程和-syscall" aria-label="Permalink to &quot;7. 观测进程、线程和 syscall&quot;">​</a></h2><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/status&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/proc/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/task&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pid,tid,psr,stat,%cpu,nvcswch,nivcswch,wchan:24,comm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>/proc/PID/status</code> 的 <code>Threads</code> 和切换计数是累计值，要按时间取差。读取其他进程受 ptrace 与挂载策略限制。Linux 主线程 TID 等于 PID，但工作线程 TID 不等于进程 PID。</p><p><code>strace</code> 跟踪 syscall：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timeout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 10s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> strace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -T</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -yy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/lili-strace.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><code>-f</code> 跟随新线程/子进程，输出量会增加。</li><li><code>-tt</code> 记录时间，<code>-T</code> 记录 syscall 内经过时间；该时间可能包含调度等待，不是纯 CPU。</li><li><code>-yy</code> 解码 fd 目标，可能暴露路径、地址和敏感对象。</li><li>附加需要 ptrace 权限，会暂停目标线程并增加开销；高吞吐生产服务只做短、窄、获授权采样。</li></ul><p>汇总模式 <code>strace -c</code> 能显示调用次数、错误数和耗时比例，却丢失请求时序。先在测试环境复现，现场采样要设 <code>timeout</code>。macOS 使用 Instruments、<code>sample</code> 或受限制的 <code>dtruss</code>，没有 Linux <code>/proc</code>/<code>strace</code> 完全等价接口。</p><h2 id="_8-语言运行时与-os-线程" tabindex="-1">8. 语言运行时与 OS 线程 <a class="header-anchor" href="#_8-语言运行时与-os-线程" aria-label="Permalink to &quot;8. 语言运行时与 OS 线程&quot;">​</a></h2><p>goroutine、Java virtual thread、协程不是 OS 线程。以 Go 为例，运行时把 goroutine 调度到一组 OS 线程；网络 poller 让等待非阻塞 socket 的 goroutine 休眠。阻塞 syscall、cgo、<code>LockOSThread</code> 仍会影响线程使用。诊断必须同时看语言运行时 profile/trace 与内核线程状态。</p><p>线程数量也不是并行度：并行执行受 CPU 数、cpuset、quota、调度和运行时设置限制。增加线程能覆盖等待，但对 CPU 饱和工作可能增加切换和 cache 失效。</p><h2 id="_9-完整案例-system-cpu-高且吞吐下降" tabindex="-1">9. 完整案例：system CPU 高且吞吐下降 <a class="header-anchor" href="#_9-完整案例-system-cpu-高且吞吐下降" aria-label="Permalink to &quot;9. 完整案例：system CPU 高且吞吐下降&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>API user CPU 25%、system CPU 55%，吞吐下降 40%。</li><li>进程有 120 个线程，无 OOM 或磁盘错误。</li><li>最近把日志从缓冲批量改为每行同步写。</li></ul><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>固定 30 秒时间窗记录吞吐、user/system CPU 和上下文切换差值。</li><li><code>pidstat -w -p PID 1 10</code> 确认切换率上升。</li><li>在预生产同负载运行 <code>strace -f -c -p PID</code> 10 秒，发现 <code>write</code>/<code>fdatasync</code> 次数与请求数成倍增长。</li><li>应用 profile 未显示计算热点；磁盘 await 同时上升。</li><li>恢复有界日志缓冲和批量刷写，并保留严重审计事件同步策略。</li></ol><h3 id="输出与验证" tabindex="-1">输出与验证 <a class="header-anchor" href="#输出与验证" aria-label="Permalink to &quot;输出与验证&quot;">​</a></h3><p>相同负载下 write syscall 数下降，system CPU 恢复 12%，吞吐和 p99 恢复。用故障注入验证进程崩溃时最多丢失的日志窗口符合约定。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若 syscall 计数不高但 system CPU 高，继续检查网络 softirq、page fault、锁/futex 和容器节流；<code>strace</code> 会改变时序，不能作为唯一证据。若同步写是审计不丢失要求，不可直接缓冲，应采用专用审计通道、批量持久化协议和故障验收。</p><h2 id="_10-常见错误" tabindex="-1">10. 常见错误 <a class="header-anchor" href="#_10-常见错误" aria-label="Permalink to &quot;10. 常见错误&quot;">​</a></h2><ul><li>把进程等同程序文件：同一可执行文件可有多个进程，exec 后 PID 仍可不变。</li><li>把 thread ID 当全局稳定业务标识：TID 会复用。</li><li>把 syscall 时间全算作内核 CPU：其中可包含睡眠和调度。</li><li>对任何 <code>EINTR</code> 无条件重试：可能违反截止时间或重复非幂等步骤。</li><li>认为 root 等于内核态，或认为容器内 root 自动拥有宿主全部能力。</li><li>看到大量线程就直接降低线程数，没有验证 runnable、等待原因和吞吐。</li></ul><h2 id="_11-练习与完成标准" tabindex="-1">11. 练习与完成标准 <a class="header-anchor" href="#_11-练习与完成标准" aria-label="Permalink to &quot;11. 练习与完成标准&quot;">​</a></h2><ol><li>写一个父进程启动子进程并回收退出状态的程序，验证正常退出与 signal 终止。</li><li>对本地程序做 5 秒 syscall 汇总，解释前三类 syscall 的输入、返回和失败。</li><li>比较一次阻塞读取前后的线程状态和自愿切换计数。</li><li>完成标准：能区分资源边界与执行流、用户/root 与用户态/内核态、syscall 耗时与 CPU 时间，并给出安全观测限制。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://man7.org/linux/man-pages/man2/syscalls.2.html" target="_blank" rel="noreferrer">Linux man-pages：syscalls(2)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man7/pthreads.7.html" target="_blank" rel="noreferrer">Linux man-pages：pthreads(7)、clone(2)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man5/proc_pid_status.5.html" target="_blank" rel="noreferrer">Linux man-pages：proc_pid_status(5)</a>（访问日期：2026-07-17）</li><li><a href="https://man7.org/linux/man-pages/man1/strace.1.html" target="_blank" rel="noreferrer">strace manual</a>（访问日期：2026-07-17）</li><li><a href="https://go.dev/src/runtime/proc.go" target="_blank" rel="noreferrer">Go runtime scheduler source</a>（访问日期：2026-07-17）</li></ul>`,50)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
